  ('real-estate-moex-01328', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於不動產經紀業為廣告行為之規範，下列敘述何者錯誤？', '["經紀業與委託人簽訂委託契約書後，方得刊登廣告及銷售", "委託契約內容與事實不符者，經紀業應依事實修正廣告內容", "經紀業如為加盟店或加盟經營者，得逕以加盟店名稱替代直營店之法定經紀業名稱，以資消費者便於辨識", "廣告對不動產之外在環境、視野或景觀之表示與事實不符者，得認定為不實廣告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01329', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於不動產經紀業違法行為之行政處罰，下列何種行為之法定最低罰鍰金額為最嚴重？', '["經紀業未將經紀人到職與異動向主管機關報請備查", "於雙方當事人簽訂租賃或買賣契約書時，經紀人未將不動產說明書交付與委託人交易之相對人", "經紀業未於營業處所設置符合法定最低人數之經紀人", "非經紀業（無經營執照）而經營仲介或代銷業務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01330', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依新修正之「不動產說明書應記載及不得記載事項」規定，下列何者並非成屋契約之應記載事項？', '["是否已辦理建物所有權第一次登記", "各期價金之履約保證機制方式，及其受託或提供擔保者", "建物型態與現況格局", "本建物（專有部分）於產權持有期間是否曾發生兇殺、自殺、一氧化碳中毒或其他非自然死亡之情形， 若有，應敘明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01331', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例規定，關於不動產經紀業者之行為規範，下列敘述何者錯誤？', '["經營仲介業務者依民法禁止雙方代理原則，不得同時接受雙方之委託進行不動產買賣", "經營代銷業務者，對於起造人或建築業委託代銷之案件，應於委託代銷契約屆滿或終止30日內，向主 管機關申報登錄成交案件實際資訊", "經紀業與委託人簽訂委託契約書後，方得刊登廣告及銷售", "經紀業不得收取差價或其他報酬，其經營仲介業務者，並應依實際成交價金或租金按中央主管機關規 定之報酬標準計收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
